	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	content := string(htmlContent)

	// Extract title
	var title string
	titleStart := strings.Index(content, "<title>")
	if titleStart != -1 {
		titleEnd := strings.Index(content[titleStart:], "</title>")
		if titleEnd != -1 {
			title = strings.TrimSpace(content[titleStart+7 : titleStart+titleEnd])
		}
	}

	// Extract description from meta tag
	var description string
	descStart := strings.Index(strings.ToLower(content), "name=\"description\"")
	if descStart == -1 {
		descStart = strings.Index(strings.ToLower(content), "name='description'")
	}
	if descStart != -1 {
		// Find the start of the content attribute
		contentStart := strings.Index(content[descStart:], "content=")
		if contentStart != -1 {
			startPos := descStart + contentStart + 8 // +8 for "content="
			if startPos < len(content) {
				quote := content[startPos]
				if quote == '"' || quote == '\'' {
					endPos := strings.Index(content[startPos+1:], string(quote))
					if endPos != -1 {
						description = strings.TrimSpace(content[startPos+1 : startPos+1+endPos])
					}
				} else {
					// Handle unquoted content (less common)
					endPos := strings.IndexAny(content[startPos:], " >")
					if endPos != -1 {
						description = strings.TrimSpace(content[startPos : startPos+endPos])
					} else {
						description = strings.TrimSpace(content[startPos:])
					}
				}
			}
		}
	}

	return title, description
}

