		"local", "internal", "intranet", "corp", "home", "lan",
	}
	for _, internal := range internalHosts {
		if strings.HasSuffix(strings.ToLower(hostname), "."+internal) || strings.EqualFold(hostname, internal) {
			return true
		}
	}

	return false
}

