package main

import (
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Fetch the URL
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Do(&http.Request{
		Method: http.MethodGet,
		URL:    parsedURL,
		Header: map[string][]string{
			"User-Agent": {"Mozilla/5.0 (compatible; URLPreviewBot/1.0)"},
		},
	})
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	content := string(htmlContent)

	// Extract title
	var title string
	titleStart := strings.Index(content, "<title>")
	if titleStart == -1 {
		titleStart = strings.Index(strings.ToLower(content), "<title>")
		if titleStart != -1 {
			contentLower := strings.ToLower(content)
			titleEnd := strings.Index(contentLower[titleStart:], "</title>")
			if titleEnd != -1 {
				title = strings.TrimSpace(content[titleStart+7 : titleStart+titleEnd])
			}
		}
	} else {
		titleEnd := strings.Index(content[titleStart:], "</title>")
		if titleEnd != -1 {
			title = strings.TrimSpace(content[titleStart+7 : titleStart+titleEnd])
		}
	}

	// Extract description from meta tag
	var description string
	descPatterns := []string{
		`name="description"`,
		`name='description'`,
		`name=description`,
	}

	contentLower := strings.ToLower(content)
	for _, pattern := range descPatterns {
		descStart := strings.Index(contentLower, pattern)
		if descStart != -1 {
			// Find the content attribute after the name attribute
			contentStart := strings.Index(contentLower[descStart:], "content=")
			if contentStart != -1 {
				contentStart += descStart + 8 // 8 is len("content=")
				if contentStart < len(contentLower) {
					quote := byte('"')
					if contentLower[contentStart] == '\'' {
						quote = '\''
					}

					if contentLower[contentStart] == '"' || contentLower[contentStart] == '\'' {
						contentStart++
						contentEnd := strings.Index(contentLower[contentStart:], string(quote))
						if contentEnd != -1 {
							description = strings.TrimSpace(content[contentStart : contentStart+contentEnd])
							break
						}
					} else {
						// Handle unquoted content (less common)
						endPos := contentStart
						for endPos < len(contentLower) && contentLower[endPos] != '>' && !strings.HasPrefix(contentLower[endPos:], " ") {
							endPos++
						}
						description = strings.TrimSpace(content[contentStart:endPos])
						break
					}
				}
			}
		}
	}

	return title, description
}

