package main

import (
	"encoding/json"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type Request struct {
	URL string `json:"url"`
}

type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(Request)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := parseHTML(body)

	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

func parseHTML(data []byte) (string, string) {
	title := ""
	description := ""

	tokenizer := html.NewTokenizer(strings.NewReader(string(data)))

	for {
		tt := tokenizer.Next()

		switch tt {
		case html.ErrorToken:
			return title, description
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.Data == "title" {
				// Get the next token which should be the text content
				if tokenizer.Next() == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			} else if token.Data == "meta" {
				// Check for name="description" or property="og:description"
				hasDescription := false
				hasOgDescription := false
				var content string

				for _, attr := range token.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						hasDescription = true
					} else if attr.Key == "property" && attr.Val == "og:description" {
						hasOgDescription = true
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}

				if hasOgDescription && description == "" {
					description = content
				} else if hasDescription && description == "" {
					description = content
				}
			}
		}
	}
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

