// isSafeURL checks if the URL points to a safe (public) destination to prevent SSRF
func isSafeURL(u *url.URL) bool {
	host := u.Hostname()
	if host == "" {
		return false
	}

	// Parse the host as an IP address
	ip := net.ParseIP(host)
	if ip == nil {
		// If it's not an IP, it's a hostname - we'll allow it but note that
		// in production you might want to implement additional DNS resolution checks
		return true
	}

	// Reject private IP ranges and loopback addresses
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return false
	}

	// Reject localhost explicitly
	if host == "localhost" {
		return false
	}

	return true
