	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create context with timeout
	ctxWithTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(ctxWithTimeout, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	// Set a user agent to avoid being blocked by some sites
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractMetadata(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractMetadata(htmlContent []byte) (string, string) {
	title := ""
	description := ""

	tokenizer := html.NewTokenizer(strings.NewReader(string(htmlContent)))

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()
		if tokenType == html.StartTagToken {
			tagName := token.DataAtom.String()
			if tagName == "title" {
				// Get the next token which should be the text content
				nextTokenType := tokenizer.Next()
				if nextTokenType == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			} else if tagName == "meta" {
				// Check for meta description
				hasName := false
				hasContent := false
				var contentValue string

				for _, attr := range token.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						hasName = true
					} else if attr.Key == "content" {
						hasContent = true
						contentValue = attr.Val
					}
				}

				if hasName && hasContent {
					description = strings.TrimSpace(contentValue)
				}

				// Also check for Open Graph description
				if !hasName {
					for _, attr := range token.Attr {
						if attr.Key == "property" && attr.Val == "og:description" {
							hasName = true
						} else if attr.Key == "content" {
							hasContent = true
							contentValue = attr.Val
						}
					}
					if hasName && hasContent && description == "" {
						description = strings.TrimSpace(contentValue)
					}
				}
			}
		}
	}

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

