// isSafeURL checks if the URL does not point to private, loopback, or link-local addresses
func isSafeURL(u *url.URL) bool {
	if u.Host == "" {
		return false
	}

	host := u.Hostname()
	ip := net.ParseIP(host)
	if ip == nil {
		// Host is a domain name, not an IP - this is generally safe but could still resolve to private IP
		// For stronger security, we would need to resolve the domain and check the resulting IP
		// However, that adds complexity and potential performance issues
		// As a basic protection, we'll allow domain names but note that this is not 100% secure against DNS rebinding
